  function App() {
    const W = window;
    const { AppShell } = W;
    const { ErrorState } = W.DataQDesignSystem_317fec;
    // nav = { name, params }. go(name, params) navigates; back links call go(parent).
    const [nav, setNav] = React.useState({ name: 'dashboard', params: {} });
    const [role, setRole] = React.useState('Admin');
    const go = React.useCallback((name, params = {}) => {
      setNav({ name, params });
      const main = document.querySelector('main');
      if (main) main.scrollTop = 0;
    }, []);

    const SCREENS = {
      dashboard: W.DashboardScreen,
      connections: W.ConnectionsScreen,
      'connection-source': W.ConnectionSourceScreen,
      'connection-config': W.ConnectionConfigScreen,
      suites: W.SuitesScreen,
