// DataQ — Suites page. The shipped two-panel list/detail: suites on the
// left, the selected suite's checks (GX expectations) on the right.
const DQs = window.DataQDesignSystem_317fec;

const SUITES = [
  { id: 's1', name: 'Daily Revenue Audit', target: 'Snowflake_Prod_01 · FCT_REVENUE', last: 'pass', checks: [
    { name: 'revenue not null', exp: 'expect_column_values_to_not_be_null', kind: 'expectation', status: 'pass' },
    { name: 'amount positive', exp: 'expect_column_values_to_be_between', kind: 'expectation', status: 'pass' },
    { name: 'row count stable', exp: 'expect_table_row_count_to_be_between', kind: 'expectation', status: 'pass' },
  ] },
  { id: 's2', name: 'Customer Ingestion Flow', target: 'AWS_S3_Landing · customers/*.parquet', last: 'fail', checks: [
    { name: 'email format', exp: 'expect_column_values_to_match_regex', kind: 'expectation', status: 'fail' },
    { name: 'id unique', exp: 'expect_column_values_to_be_unique', kind: 'expectation', status: 'critical' },
    { name: 'no nulls in pk', exp: 'expect_column_values_to_not_be_null', kind: 'expectation', status: 'pass' },
  ] },
  { id: 's3', name: 'ML Feature Store', target: 'Databricks_UC_Main · features.user_emb', last: 'warn', checks: [
    { name: 'freshness < 1h', exp: 'expect_column_max_to_be_between', kind: 'expectation', status: 'warn' },
    { name: 'embedding dim', exp: 'expect_column_values_to_be_of_type', kind: 'expectation', status: 'pass' },
  ] },
  { id: 's4', name: 'GDPR Compliance Check', target: 'Postgres_EU_West · users', last: 'pass', checks: [
    { name: 'pii masked', exp: 'expect_column_values_to_match_regex', kind: 'expectation', status: 'pass' },
  ] },
];

function SuiteListItem({ s, active, onClick }) {
  const { StatusBadge } = DQs;
  return (
    <button onClick={onClick} style={{
      display: 'flex', flexDirection: 'column', gap: 6, width: '100%', textAlign: 'left',
      padding: '14px 16px', border: 'none', borderRadius: 'var(--radius)', cursor: 'pointer',
      background: active ? 'var(--bg-selected)' : 'transparent',
      boxShadow: active ? 'inset 0 0 0 1px var(--indigo-200)' : 'none',
    }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 8 }}>
        <span style={{ fontSize: 14, fontWeight: 600, color: active ? 'var(--indigo-700)' : 'var(--text-primary)' }}>{s.name}</span>
        <StatusBadge status={s.last} variant="soft" />
      </div>
      <span style={{ fontSize: 12, color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>{s.target}</span>
    </button>
  );
}

function SuiteDetail({ s, go }) {
  const { Card, DataTable, StatusBadge, Tag, Button } = DQs;
  const [shareOpen, setShareOpen] = React.useState(false);
  const ShareSuiteDrawer = window.ShareSuiteDrawer;
  const cols = [
    { key: 'name', header: 'Check', render: (v) => <strong style={{ color: 'var(--text-primary)', fontWeight: 600 }}>{v}</strong> },
    { key: 'exp', header: 'Expectation', mono: true, render: (v) => <span style={{ color: 'var(--text-secondary)', fontSize: 12 }}>{v}</span> },
    { key: 'kind', header: 'Kind', width: 110, render: (v) => <Tag tone="outline">{v}</Tag> },
    { key: 'status', header: 'Last', width: 110, render: (v) => <StatusBadge status={v} variant="soft" /> },
  ];
  return (
    <Card padding={0} style={{ overflow: 'hidden' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', padding: '18px 20px', borderBottom: '1px solid var(--divider)' }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 600, color: 'var(--text-primary)' }}>{s.name}</div>
          <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 4, fontFamily: 'var(--font-mono)' }}>{s.target}</div>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <Button variant="ghost" size="sm" iconLeft={<window.Icon.share size={13} />} onClick={() => setShareOpen(true)}>Share</Button>
          <Button variant="secondary" size="sm" onClick={() => go('suite-check', { suiteName: s.name })}>Add Check</Button>
          <Button variant="primary" size="sm" iconLeft={<window.Icon.play size={13} />}>Run</Button>
        </div>
      </div>
      <DataTable columns={cols} rows={s.checks} />
      {ShareSuiteDrawer && <ShareSuiteDrawer open={shareOpen} onClose={() => setShareOpen(false)} suiteName={s.name} />}
    </Card>
  );
}

function SuitesScreen({ go }) {
  const { Button } = DQs;
  const [sel, setSel] = React.useState('s2');
  const suite = SUITES.find((s) => s.id === sel) || SUITES[0];
  return (
    <div style={{ maxWidth: 1200, margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <h1 style={{ margin: 0, fontSize: 24, fontWeight: 600, color: 'var(--text-primary)' }}>Suites</h1>
          <div style={{ fontSize: 14, color: 'var(--text-secondary)', marginTop: 4 }}>42 suites · <span style={{ color: 'var(--status-pass)', fontWeight: 600 }}>38 active</span> · <span style={{ color: 'var(--status-fail)', fontWeight: 600 }}>4 failing</span></div>
        </div>
        <Button variant="primary" iconLeft={<window.Icon.plus size={15} />} onClick={() => go('suite-new')}>New Suite</Button>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '320px 1fr', gap: 16, alignItems: 'start' }}>
        <DQs.Card padding={6}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
            {SUITES.map((s) => <SuiteListItem key={s.id} s={s} active={s.id === sel} onClick={() => setSel(s.id)} />)}
          </div>
        </DQs.Card>
        <SuiteDetail s={suite} go={go} />
      </div>
    </div>
  );
}

Object.assign(window, { SuitesScreen });

