{"method":"get_file","path":"templates/app/CheckFlow.jsx","content":"// DataQ — Add Check / Define Rules (full-page). Mirrors the Figma "new suite
// define rules" frame: pick a GX expectation, fill spec-driven config, set a
// severity tier, dry-run a preview. From expectationCatalog.ts. Exports
// window.CheckScreen.
const DQchk = window.DataQDesignSystem_317fec;

const CATALOG = [
  { type: 'expect_column_values_to_not_be_null', label: 'Column values not null', category: 'Column values', desc: 'Every value in the column is non-null.', fields: [{ name: 'column', label: 'Column', type: 'string' }] },
  { type: 'expect_column_values_to_be_unique', label: 'Column values unique', category: 'Column values', desc: 'Values in the column are distinct.', fields: [{ name: 'column', label: 'Column', type: 'string' }] },
  { type: 'expect_column_values_to_be_between', label: 'Column values in range', category: 'Column values', desc: 'Numeric values fall within [min, max].', fields: [{ name: 'column', label: 'Column', type: 'string' }, { name: 'min_value', label: 'Minimum', type: 'number', optional: true }, { name: 'max_value', label: 'Maximum', type: 'number', optional: true }] },
  { type: 'expect_column_values_to_be_in_set', label: 'Column values in set', category: 'Column values', desc: 'Every value is one of an allowed set.', fields: [{ name: 'column', label: 'Column', type: 'string' }, { name: 'value_set', label: 'Allowed values', type: 'list', help: 'Comma-separated list of permitted values.' }] },
  { type: 'expect_column_values_to_match_regex', label: 'Column values match regex', category: 'Column values', desc: 'Every value matches the regex.', fields: [{ name: 'column', label: 'Column', type: 'string' }, { name: 'regex', label: 'Regex', type: 'string' }] },
  { type: 'expect_table_row_count_to_be_between', label: 'Table row count in range', category: 'Table shape', desc: 'The table row count falls within [min, max].', fields: [{ name: 'min_value', label: 'Minimum rows', type: 'number', optional: true }, { name: 'max_value', label: 'Maximum rows', type: 'number', optional: true }] },
];
const CATEGORIES = ['Column values', 'Table shape'];

function CheckScreen({ go, params }) {
  const { Card, Button, Input, Select, Tag, StatusBadge } = DQchk;
  const { PageHeader } = window;
  const suiteName = (params && params.suiteName) || 'suite';
  const [expType, setExpType] = React.useState(CATALOG[0].type);
  const [severity, setSeverity] = React.useState('fail');
  const [dry, setDry] = React.useState(null);
  const spec = CATALOG.find((e) => e.type === expType);
  const grouped = CATEGORIES.map((c) => ({ label: c, options: CATALOG.filter((e) => e.category === c).map((e) => ({ value: e.type, label: e.label })) }));

  return (
    <div style={{ maxWidth: 720, margin: '0 auto' }}>
      <PageHeader backLabel="Suites" onBack={() => go('suites')}
        title="Add Check" subtitle={`Define a rule for ${suiteName}`} />
      <Card padding={24}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <Input label="Check name" placeholder="revenue not null" />

          <label style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--text-primary)' }}>Expectation</span>
            <span style={{ position: 'relative' }}>
              <select value={expType} onChange={(e) => setExpType(e.target.value)} style={{
                width: '100%', height: 40, padding: '0 36px 0 12px', boxSizing: 'border-box', appearance: 'none', WebkitAppearance: 'none',
                background: 'var(--bg-card)', border: '1px solid var(--border-input)', borderRadius: 'var(--radius)',
                fontFamily: 'var(--font-mono)', fontSize: 13, color: 'var(--text-primary)', cursor: 'pointer',
              }}>
                {grouped.map((g) => (
                  <optgroup key={g.label} label={g.label}>
                    {g.options.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
                  </optgroup>
                ))}
              </select>
              <span style={{ position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none', color: 'var(--text-muted)' }}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round"><polyline points="6 9 12 15 18 9"/></svg>
              </span>
            </span>
            <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{spec.desc}</span>
          </label>

          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <Tag mono tone="outline">{spec.type}</Tag>
            <Tag tone="neutral">expectation</Tag>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
            {spec.fields.map((f, i) => (
              <Input key={f.name} label={f.label + (f.optional ? ' (optional)' : '')} mono={f.name === 'column'}
                placeholder={f.type === 'number' ? '0' : f.type === 'list' ? 'USD, EUR, GBP' : f.name}
                hint={f.help} type={f.type === 'number' ? 'number' : 'text'}
                style={{ gridColumn: (f.type === 'list' || spec.fields.length === 1) ? '1 / -1' : 'auto' }} />
            ))}
          </div>

          <Select label="Severity tier" value={severity} onChange={(e) => setSeverity(e.target.value)}
            hint="On breach, the result is banded to this tier (ADR 0005)."
            options={[{ value: 'warn', label: 'warn — weight 0.5' }, { value: 'fail', label: 'fail — weight 1.0' }, { value: 'critical', label: 'critical — weight 2.0' }]} />

          {dry && (
            <div style={{ padding: '12px 14px', background: 'var(--bg-subtle)', border: '1px solid var(--border)', borderRadius: 'var(--radius)' }}>
              <div style={{ fontSize: 12, fontWeight: 600, letterSpacing: '.04em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 8 }}>Dry-run preview</div>
              {dry === 'running' ? <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>Sampling 10,000 rows…</span> : (
                <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                  <StatusBadge status="pass" variant="soft" />
                  <span style={{ fontSize: 13, color: 'var(--text-body)', fontFamily: 'var(--font-mono)' }}>unexpected: 0 / 9,842 · observed 100%</span>
                </div>
              )}
            </div>
          )}
        </div>

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 24, paddingTop: 20, borderTop: '1px solid var(--divider)' }}>
          <Button variant="secondary" onClick={() => { setDry('running'); setTimeout(() => setDry('pass'), 700); }}>Dry run</Button>
          <Button variant="primary" onClick={() => go('suites')}>Add Check</Button>
        </div>
      </Card>
    </div>
  );
}

Object.assign(window, { CheckScreen });
