{"method":"get_file","path":"templates/error/index.html","content":"<!-- @template name="DataQ Error Pages" description="Standard 4xx & 5xx HTTP error pages in the app shell — switchable across 404/403/401/429/500/503/504 with recovery actions and a request id." -->
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>DataQ — Error</title>
<style>
  * { box-sizing: border-box; }
  html, body { margin: 0; height: 100%; font-family: var(--font-sans); color: var(--text-body); background: var(--bg-app); }
  #root { height: 100%; }
</style>
<script src="https://unpkg.com/react@18.3.1/umd/react.development.js" integrity="sha384-hD6/REDACTED/6onKUg4lLsHAs9EBPT82L" crossorigin="anonymous"></script>
<script src="https://unpkg.com/react-dom@18.3.1/umd/react-dom.development.js" integrity="REDACTED" crossorigin="anonymous"></script>
<script src="https://unpkg.com/@babel/standalone@7.29.0/babel.min.js" integrity="sha384-m08KidiNqLdpJqLq95G/LEi8Qvjl/REDACTED" crossorigin="anonymous"></script>
<script src="./ds-base.js"></script>
</head>
<body>
<div id="root"></div>
<script type="text/babel" data-presets="react">
  const { ErrorState, SegmentedControl, Tag } = window.DataQDesignSystem_317fec;

  // The standard DataQ error catalog — 4xx (client) and 5xx (server).
  const ERRORS = {
    '400': { tone: 'client', title: 'Bad request', message: 'The request was malformed — a parameter or filter is invalid. Adjust your input and try again.' },
    '401': { tone: 'client', title: 'Session expired', message: 'Your Azure AD session has ended. Sign in again to continue monitoring your data.', primary: { label: 'Sign in', href: '../app/index.html' } },
    '403': { tone: 'client', title: 'Access denied', message: "You don't have permission to view this suite or workspace. Ask an admin to grant access via RBAC." },
    '404': { tone: 'client', title: 'Page not found', message: "The suite, connection, or page you're looking for doesn't exist or has moved." },
    '429': { tone: 'client', title: 'Too many requests', message: "You've hit the rate limit. Pause for a moment before retrying — scheduled runs are unaffected." },
    '500': { tone: 'server', title: 'Something went wrong on our end', message: 'DataQ hit an unexpected error processing your request. The engineering team has been notified automatically.' },
    '502': { tone: 'server', title: 'Bad gateway', message: 'An upstream service returned an invalid response. This is usually transient — retry in a few seconds.' },
    '503': { tone: 'server', title: 'Service unavailable', message: 'DataQ is temporarily down for maintenance or under heavy load. Monitoring continues; the console will return shortly.' },
    '504': { tone: 'server', title: 'Gateway timeout', message: 'A datasource or orchestration provider took too long to respond. Check the connection, then retry.' },
  };

  // Minimal shell chrome (header + watermark) so the error sits in-product.
  function Shell({ children }) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: 'var(--bg-app)' }}>
        <header style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '0 24px', height: 56, flex: 'none', background: 'var(--bg-card)', borderBottom: '1px solid var(--border)' }}>
          <a href="../app/index.html" style={{ display: 'flex', alignItems: 'center', gap: 10, textDecoration: 'none' }}>
            <img src="../../assets/logo/dataq-mark.svg" width="28" height="28" alt="" />
            <span style={{ fontWeight: 700, fontSize: 17, color: 'var(--ink)' }}>DataQ</span>
          </a>
        </header>
        <main style={{ flex: 1, position: 'relative', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <img src="../../assets/logo/dataq-mark.svg" aria-hidden="true" style={{ position: 'absolute', right: -90, bottom: -90, width: 360, opacity: 0.05 }} />
          <div style={{ position: 'relative', width: '100%' }}>{children}</div>
        </main>
      </div>
    );
  }

  function ErrorPage() {
    const [code, setCode] = React.useState('404');
    const e = ERRORS[code];
    const codes = Object.keys(ERRORS);

    const primary = e.primary || (e.tone === 'server'
      ? { label: 'Retry', onClick: () => setCode(code) }
      : { label: 'Back to Results', href: '../app/index.html' });
    const secondary = e.tone === 'server'
      ? { label: 'View status page', href: '#' }
      : { label: 'Go to Connections', href: '../app/index.html' };

    return (
      <Shell>
        {/* demo switcher — not part of the shipped page */}
        <div style={{ position: 'absolute', top: 16, left: '50%', transform: 'translateX(-50%)', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 8, zIndex: 5 }}>
          <span style={{ fontSize: 11, fontWeight: 600, letterSpacing: '.06em', textTransform: 'uppercase', color: 'var(--text-muted)' }}>Status code · demo</span>
          <SegmentedControl size="sm" value={code} onChange={setCode}
            options={codes.map((c) => ({ value: c, label: c }))} />
        </div>

        <ErrorState
          code={code}
          tone={e.tone}
          title={e.title}
          message={e.message}
          primaryAction={primary}
          secondaryAction={secondary}
          requestId={e.tone === 'server' ? 'req_9f2a1c7b3e' : null}
        />
      </Shell>
    );
  }

  ReactDOM.createRoot(document.getElementById('root')).render(<ErrorPage />);
</script>
</body>
</html>
