1	import type { ResultStatus, RunStatus } from '../../api/runs';
2	
3	/**
4	 * Pure presentation helpers for the Results surface — kept framework-free so the
5	 * status→colour mapping and the timing formatters can be unit-tested without
6	 * rendering antd.
7	 */
8	
9	/** antd Tag colour per run execution status. */
10	export const RUN_STATUS_COLORS: Record<RunStatus, string> = {
11	  queued: 'default',
12	  running: 'processing',
13	  succeeded: 'success',
14	  failed: 'error',
15	  cancelled: 'warning',
16	};
17	
18	/**
19	 * antd `Progress` bar status per run lifecycle state. A `Record` (not a switch)
20	 * so a new `RunStatus` value is a compile error here rather than silently
21	 * falling through to `'normal'`.
22	 */
23	export const RUN_BAR_STATUS: Record<RunStatus, 'success' | 'exception' | 'active' | 'normal'> = {
24	  queued: 'normal',
25	  running: 'active',
26	  succeeded: 'success',
27	  failed: 'exception',
28	  cancelled: 'exception',
29	};
30	
31	/** antd Tag colour per result severity / operational status (ADR 0005 / #122). */
32	export const RESULT_STATUS_COLORS: Record<ResultStatus, string> = {
33	  pass: 'success',
34	  warn: 'warning',
35	  fail: 'error',
36	  critical: 'magenta',
37	  skip: 'default',
38	  error: 'volcano',
39	};
40	
41	/** Orchestrator pipeline-run status → colour (provider-agnostic value set). */
42	export function pipelineStatusColor(status: string): string {
43	  switch (status) {
44	    case 'succeeded':
45	      return 'success';
46	    case 'failed':
47	      return 'error';
48	    case 'running':
49	      return 'processing';
50	    case 'cancelled':
51	      return 'warning';
52	    default:
53	      return 'default';
54	  }
55	}
56	
57	/**
58	 * Render an unknown scalar (a GX observed/expected value, a profiled min/max or
59	 * top value) for display: an em dash for null/undefined, JSON for objects, the
60	 * `String` form otherwise. Falsy scalars (`0`, `false`, `''`) render as
61	 * themselves — not collapsed to the em dash — so a real zero isn't mistaken for
62	 * "no value". The em-dash sentinel matches `formatTimestamp` / `formatDuration`.
63	 */
64	export function formatScalar(value: unknown): string {
65	  if (value === null || value === undefined) return '—';
66	  return typeof value === 'object' ? JSON.stringify(value) : String(value);
67	}
68	
69	/** Absolute timestamp as a locale string, or an em dash when absent. */
70	export function formatTimestamp(iso: string | null): string {
71	  if (!iso) return '—';
72	  const d = new Date(iso);
73	  return Number.isNaN(d.getTime()) ? '—' : d.toLocaleString();
74	}
75	
76	/**
77	 * Run duration (finished − started) as a compact human string: `850ms`, `12s`,
78	 * `1m 3s`. Returns an em dash when either bound is missing (queued / never
79	 * finished) or the interval is negative (clock skew).
80	 */
81	export function formatDuration(startedAt: string | null, finishedAt: string | null): string {
82	  if (!startedAt || !finishedAt) return '—';
83	  const ms = new Date(finishedAt).getTime() - new Date(startedAt).getTime();
84	  if (Number.isNaN(ms) || ms < 0) return '—';
85	  if (ms < 1000) return `${ms}ms`;
86	  const totalSeconds = Math.round(ms / 1000);
87	  if (totalSeconds < 60) return `${totalSeconds}s`;
88	  const minutes = Math.floor(totalSeconds / 60);
89	  const seconds = totalSeconds % 60;
90	  return `${minutes}m ${seconds}s`;
91	}
