        <span style={{ fontSize: 18, fontWeight: 700, color: 'var(--text-primary)' }}>Recent Runs</span>
        <IconButton ariaLabel="Refresh"><window.Icon.refresh size={16} /></IconButton>
      </div>
      <DataTable columns={cols} rows={rows} onRowClick={(r) => onOpen && onOpen(r)} />
